const EXPECTED = $env.MAGNIX_WEBHOOK_TOKEN || '';
const headers = $input.first().json.headers || {};
const auth = headers.authorization || headers.Authorization || '';
if (EXPECTED && auth !== `Bearer ${EXPECTED}`) {
  throw new Error('Unauthorized: invalid MAGNIX_WEBHOOK_TOKEN');
}

const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;

const uid = String(body.uid || '').trim();
const uid_source = String(body.uid_source || 'unknown').trim();
if (!uid) {
  throw new Error('Validation: uid is required');
}

const text = String(body.text ?? body.message ?? '').trim();
const meta = body.meta && typeof body.meta === 'object' ? body.meta : {};
const consent_basis = body.consent_basis || meta.consent_basis || null;

const normalized_key = `${uid_source}:${uid}`;
const captured_at = body.captured_at || new Date().toISOString();

return [{
  json: {
    uid,
    uid_source,
    normalized_key,
    captured_at,
    text,
    meta,
    consent_basis,
    status: 'raw',
  },
}];

const RULES = [
  { segment: 'noxh_income', score: 80, interest_key: 'thu_nhap_noxh', patterns: [/thu nhập|lương|vay ngân hàng|noxh|nhà ở xã hội/i] },
  { segment: 'valuation', score: 70, interest_key: 'dinh_gia_tham_dinh', patterns: [/định giá|thẩm định|chứng thư/i] },
  { segment: 'sme_credit', score: 75, interest_key: 'room_tin_dung_sme', patterns: [/room tín dụng|doanh nghiệp|\bsme\b/i] },
  { segment: 'general_inbound', score: 55, interest_key: 'quan_tam_bds', patterns: [/giá|\bcăn\b|m²|m2|block|dự án/i] },
];

function classifyText(text) {
  const t = (text || '').normalize('NFC').toLowerCase();
  let best = { segment: 'unclassified', score: 0, interest_key: 'unknown', matched: [] };
  for (const rule of RULES) {
    for (const re of rule.patterns) {
      if (re.test(t)) {
        if (rule.score > best.score) {
          best = {
            segment: rule.segment,
            score: rule.score,
            interest_key: rule.interest_key,
            matched: [re.source],
          };
        }
        break;
      }
    }
  }
  return best;
}

const items = $input.all();
return items.map((item) => {
  const text = item.json.text ?? '';
  const result = classifyText(text);
  const needs_llm =
    (result.segment === 'unclassified' && text.length > 0) ||
    (result.score >= 40 && result.score <= 59);
  return {
    json: {
      ...item.json,
      ...result,
      needs_llm,
    },
  };
});

const j = $input.first().json;
return [{
  json: {
    ok: true,
    classify: {
      segment: j.segment,
      score: j.score,
      interest_key: j.interest_key || j.segment,
    },
    classify_method: 'regex',
  },
}];

