}];

const skeleton = $('Auth & Enrich Skeleton').first().json;
const item = $input.first().json;

if (!item.ok || !item.classify) {
  throw new Error('Merge skipped: classify not ok');
}

const { segment, score, interest_key } = item.classify;
const method = item.classify_method || 'regex';

const FORBIDDEN = [
  /cam kết.*duyệt/i,
  /lãi suất\s*\d+([.,]\d+)?\s*%/i,
];

const text = skeleton.text || '';
const l0_hits = FORBIDDEN.filter((re) => re.test(text)).map((re) => re.source);

let status = 'classified';
if (score < 60) status = 'review';
if (l0_hits.length > 0) status = 'review';

const record = {
  uid: skeleton.uid,
  uid_source: skeleton.uid_source,
  normalized_key: skeleton.normalized_key,
  captured_at: skeleton.captured_at,
  text,
  segment,
  score,
  interest_key,
  tags: [segment],
  meta: skeleton.meta ?? {},
  classify_method: method,
  consent_basis: skeleton.consent_basis ?? null,
  status,
  l0_forbidden_hits: l0_hits,
};

return [{ json: { ok: true, data: record, record } }];

const base = String(
  $env.HOUSEX_PUBLIC_URL || $env.NEXT_PUBLIC_SITE_URL || 'https://timnhaxahoi.com',
).replace(/\/$/, '');
const secret = String($env.MAGNIX_INGEST_SECRET || '').trim();
const url = `${base}/api/ingest/magnix-lead`;

if (!secret) {
  throw new Error('MAGNIX_INGEST_SECRET is required for Postgres ingest');
}

const results = [];

for (const item of $input.all()) {
  const raw = item.json;

  if (!raw.ok) {
    results.push({
      json: {
        ok: false,
        error: raw.error || 'SKIP_INGEST',
        message: raw.message || 'Classify or merge failed',
        normalized_key: raw.normalized_key || null,
      },
    });
    continue;
  }

  const record =
    raw.data && typeof raw.data === 'object'
      ? raw.data
      : raw.record && typeof raw.record === 'object'
        ? raw.record
        : null;

  if (!record?.normalized_key) {
    results.push({
      json: { ok: false, error: 'MISSING_RECORD', message: 'No merged UID record' },
    });
    continue;
  }

  const payload = {
    uid: String(record.uid ?? ''),
    uid_source: String(record.uid_source ?? 'unknown'),
    normalized_key: String(record.normalized_key),
    captured_at: String(record.captured_at ?? new Date().toISOString()),
    text: record.text ?? null,
    segment: String(record.segment ?? 'unclassified'),
    score: Number(record.score ?? 0),
    interest_key: record.interest_key ?? null,
    tags: Array.isArray(record.tags) ? record.tags : [],
    meta: record.meta && typeof record.meta === 'object' ? record.meta : {},
    classify_method: String(record.classify_method ?? 'regex'),
    consent_basis: record.consent_basis ?? null,
    status: String(record.status ?? 'classified'),
  };

  const nk = payload.normalized_key;

  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: {
        'Content-Type': 'application/json',
        'x-magnix-ingest-secret': secret,
      },
      body: payload,
      json: true,
      timeout: 20000,
    });

    const row = res?.data ?? res;
    results.push({
      json: {
        ok: true,
        storage: 'postgres_housex',
        action: 'upsert',
        id: row?.id ?? null,
        normalized_key: row?.normalized_key ?? nk,
        status: row?.status ?? payload.status,
        record: payload,
      },
    });
  } catch (e) {
    const status = e.statusCode ?? e.httpCode ?? null;
    results.push({
      json: {
        ok: false,
        error: 'HOUSEX_INGEST_FAILED',
        message: String(e.message || 'HouseX ingest request failed'),
        http_status: status,
        normalized_key: nk,
      },
    });
  }
}

return results;

const item = $input.first().json;
const record = item.data && typeof item.data === 'object' ? item.data : item;

if (!record.normalized_key) {
  return [{ json: { drive_skip: true, reason: 'no normalized_key' } }];
}

const folderId = $env.GOOGLE_DRIVE_ARCHIVE_FOLDER_ID || '';
if (!folderId || $env.MAGNIX_DRIVE_BACKUP === 'false') {
  return [{ json: { drive_skip: true, reason: 'backup disabled or no folder id' } }];
}

const safeName = String(record.normalized_key).replace(/[^a-zA-Z0-9._-]/g, '_');
const fileName = `${safeName}.jsonl`;
const content = `${JSON.stringify(record)}\n`;
const binaryData = Buffer.from(content, 'utf8').toString('base64');

return [{
  json: {
    fileName,
    normalized_key: record.normalized_key,
    drive_folder_id: folderId,
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'application/x-ndjson',
      fileName,
    },
  },
}];

const item = $input.first().json;

return [{
  json: {
    ok: item.ok === true,
    storage: item.storage || (item.ok ? 'postgres_housex' : undefined),
    action: item.action,
    id: item.id,
    normalized_key: item.normalized_key,
    status: item.status,
    record: item.record,
    error: item.ok ? undefined : item.error,
    message: item.ok ? undefined : item.message,
    http_status: item.http_status,
  },
}];
